import { ChatOpenAI } from "langchain/chat_models/openai";
import { LLMChain } from "langchain/chains";
import { verify } from "vex-sdk";

const llm = new ChatOpenAI({ modelName: "gpt-4" });
const chain = new LLMChain({ llm, prompt: pricingPrompt });

const rawResult = await chain.call({ product: "iPhone 15" });
const verified = await verify({
  input: rawResult.text,
  guards: [
    "ada:accessible_format",
    "consistent:json_schema",
    "context_length:<4000"
  ],
  context: { schema: pricingSchema }
});
return verified.output;
